#include <bits/stdc++.h>
using namespace std;

const int N=1e6+10,mod=1e9+7;

int t,n,m,fac[N],inv[N],f[N];

int quick_mi(int a,int b){
    long long ans=1,base=a;
    while(b){
        if(b&1)
            ans=ans*base%mod;
        b>>=1,base=base*base%mod;
    }
    return ans;
}

void init(){
    fac[0]=1;
    for(int i=1;i<N;i++)
        fac[i]=1LL*fac[i-1]*i%mod;
    inv[N-1]=quick_mi(fac[N-1],mod-2);
    //printf("%d\n",inv[N-1]);
    for(int i=N-2;i>=0;i--)
        inv[i]=1LL*inv[i+1]*(i+1)%mod;
    f[0]=1;
    for(int i=1,xs=-1;i<N;i++,xs=-xs)
        f[i]=((f[i-1]+xs*inv[i])%mod+mod)%mod;
}

int main(){
    init();
    scanf("%d",&t);
    while(t--){
        int n,m;
        scanf("%d%d",&n,&m);
        if(n<m){
            printf("0");
            continue;
        }
        //printf("%d %d %d\n",fac[n],inv[m],f[n-m]);
        printf("%d\n",1LL*fac[n]*inv[m]%mod*f[n-m]%mod);
    }
    return 0;
}
